CREATE TABLE tasks (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), title text NOT NULL, notes text, due_at timestamptz, reminder_at timestamptz, priority text NOT NULL DEFAULT 'normal', status text NOT NULL DEFAULT 'open', source text NOT NULL DEFAULT 'manual', prospect_id uuid REFERENCES prospects(id) ON DELETE SET NULL, school_id uuid REFERENCES schools(id) ON DELETE SET NULL, director_id uuid REFERENCES directors(id) ON DELETE SET NULL, completed_at timestamptz, created_at timestamptz NOT NULL DEFAULT now(), updated_at timestamptz NOT NULL DEFAULT now()); CREATE INDEX tasks_status_due_index ON tasks(status, due_at); CREATE INDEX tasks_priority_index ON tasks(priority);
CREATE TABLE task_recurrences (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), task_id uuid NOT NULL REFERENCES tasks(id) ON DELETE CASCADE, rule text NOT NULL, next_run_at timestamptz, created_at timestamptz NOT NULL DEFAULT now());
CREATE TABLE automation_rules (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), name text NOT NULL, trigger text NOT NULL, is_enabled boolean NOT NULL DEFAULT false, configuration jsonb NOT NULL DEFAULT '{}'::jsonb, created_at timestamptz NOT NULL DEFAULT now()); CREATE TABLE automation_runs (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), rule_id uuid NOT NULL REFERENCES automation_rules(id) ON DELETE CASCADE, status text NOT NULL, details jsonb NOT NULL DEFAULT '{}'::jsonb, ran_at timestamptz NOT NULL DEFAULT now());
